sql:
SELECT sa2_code
FROM sa2_regions
WHERE state_name = 'New South Wales';

SELECT sa2_code, AVG(income_aud) AS average_income
FROM income_data
GROUP BY sa2_code;

SELECT sa2_code, time_q1, time_q2, time_q3, time_q4
FROM transport_data
ORDER BY time_q1 ASC, time_q2 ASC, time_q3 ASC, time_q4 ASC;

SELECT state_name
FROM sa2_regions
ORDER BY state_code DESC;

SELECT state_name
FROM sa2_regions
ORDER BY state_name ASC;

SELECT sa2_code, ATAN2(time_q1, time_q2) AS atan2_value
FROM transport_data
ORDER BY atan2_value DESC;

SELECT sa2_name16, population_density
FROM sa2_regions
WHERE state_name = 'Victoria';

SELECT p.sa2_code, AVG(p.median_male_age) AS avg_median_male_age, AVG(p.median_female_age) AS avg_median_female_age
FROM population_data p
GROUP BY p.sa2_code;

SELECT sa2_code, persons_num 
FROM population_data 
WHERE sa2_code = 'XYZ';

SELECT percentage_person_aged_0_14, percentage_person_aged_15_64, percentage_person_aged_65_plus, literacy_rate, average_years_of_education
FROM education_data
WHERE sa2_code = '1';

SELECT sa2_regions.sa2_name16, population_data.persons_num 
FROM sa2_regions
JOIN population_data ON sa2_regions.sa2_code = population_data.sa2_code;

SELECT sa2_regions.sa2_name16, transport_data.public_transport_coverage, transport_data.average_commute_time
FROM sa2_regions
JOIN transport_data ON sa2_regions.sa2_code = transport_data.sa2_code;

SELECT sa2_regions.sa2_name16, income_data.income_quintiles
FROM sa2_regions
JOIN income_data ON sa2_regions.sa2_code = income_data.sa2_code;

SELECT r.area_sq_km, r.population_density, p.persons_num, p.median_persons_age
FROM sa2_regions r
JOIN population_data p ON r.sa2_code = p.sa2_code;

SELECT r.sa2_name16, e.literacy_rate, e.average_years_of_education
FROM sa2_regions r
JOIN education_data e ON r.sa2_code = e.sa2_code;

SELECT sa2_code, employment_rate
FROM employment_data
ORDER BY sa2_code, employment_rate DESC;
